// Desempivota el Sheet wide-format (12 columnas de meses) a long-format
// (una fila por mes con inversión > 0). Detecta líneas de costo por nombre
// del formato y separa en tipo='media' vs tipo='costo'.

const MONTHS = {
  'Enero': 1, 'Febrero': 2, 'Marzo': 3, 'Abril': 4,
  'Mayo': 5, 'Junio': 6, 'Julio': 7, 'Agosto': 8,
  'Septiembre': 9, 'Octubre': 10, 'Noviembre': 11, 'Diciembre': 12,
};

// Año por default — el Sheet de Drean tiene un header '2026' arriba; si en
// el futuro cambia, ajustar acá o leer de una celda del Sheet.
const YEAR = 2026;

// Patrones que identifican líneas de costo (no de media)
const COSTO_PATTERNS = [
  /percep/i,      // PERCEPCIÓN IIBB
  /iibb/i,
  /impuesto/i,    // Impuesto al cheque
  /cheque/i,
  /tech\s*fee/i,  // Tech Fee Programm / YouTube
  /comisi/i,      // Comisión Agencia
];

const esCosto = (formato) => {
  if (!formato) return false;
  return COSTO_PATTERNS.some((re) => re.test(String(formato)));
};

// Líneas "resumen" del Sheet que NO queremos sincronizar (Total OFF, Total ON, etc.)
const SKIP_PATTERNS = [
  /^Total\s+/i,
  /^Total\s*$/i,
  /^Subtotal/i,
];

const esSkip = (sistema, formato) => {
  const txt = [sistema, formato].filter(Boolean).join(' ');
  return SKIP_PATTERNS.some((re) => re.test(txt));
};

const parseCurrency = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = String(v).trim();
  if (s === '-' || s === '$-' || s === '$ -' || s === '$0' || s === '$ 0') return 0;
  // Limpia $ . , y espacios — formato AR usa . como separador de miles y , como decimal
  const cleaned = s.replace(/[\s$]/g, '').replace(/\./g, '').replace(',', '.');
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
};

const output = [];
let skipped = 0;
let emptyRows = 0;

for (const item of items) {
  const r = item.json;

  const campania   = String(r['Campaña'] || r['Campana'] || r['Categoría'] || '').trim();
  const rol        = String(r['Rol Of Comms'] || r['Rol'] || '').trim() || null;
  const touchpoint = String(r['TouchPoint'] || r['Touchpoint'] || '').trim() || null;
  const sistema    = String(r['Sistema'] || '').trim();
  const formato    = String(r['Formato & Channel'] || r['Formato'] || r['Formato y Channel'] || '').trim();

  if (!campania) { emptyRows++; continue; }
  if (esSkip(sistema, formato)) { skipped++; continue; }

  const tipo = esCosto(formato) ? 'costo' : 'media';

  for (const [monthName, monthNum] of Object.entries(MONTHS)) {
    const raw = r[monthName];
    const inversion = parseCurrency(raw);
    if (inversion === null || inversion === 0) continue;

    const fecha = `${YEAR}-${String(monthNum).padStart(2, '0')}-01`;
    output.push({
      json: {
        fecha,
        campania,
        rol,
        touchpoint,
        sistema: sistema || null,
        formato: formato || null,
        inversion,
        tipo,
      },
    });
  }
}

if (skipped || emptyRows) {
  console.warn(`Planning media unpivot: ${output.length} filas generadas. Skipped (Total/Subtotal): ${skipped}. Empty rows: ${emptyRows}.`);
}

return output;
